#include<bits/stdc++.h>
#define gmx getmax
#define gmn getmin
using namespace std;
long long a[100010],b[100010];
long long A[100010],B[100010];
struct st
{
    long long lg[100010];
    long long f[100010][22],f1[100010][22];
    void init(long long a[],long long n)
    {
        lg[1]=0;
        for(long long i=2;i<=n;i++)
        {
            lg[i]=lg[i/2]+1;
        }
        for(long long i=1;i<=n;i++)
        {
            f[i][0]=f1[i][0]=a[i];
        }
        for(long long j=1;j<=lg[n];j++)
        {
            for(long long i=1;i<=n-(1<<j)+1;i++)
            {
                f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
                f1[i][j]=min(f1[i][j-1],f1[i+(1<<(j-1))][j-1]);
            }
        }
    }
    long long getmax(long long l,long long r)
    {
        long long temp=lg[r-l+1];
        return max(f[l][temp],f[r-(1<<temp)+1][temp]);
    }
    long long getmin(long long l,long long r)
    {
        long long temp=lg[r-l+1];
        return min(f1[l][temp],f1[r-(1<<temp)+1][temp]);
    }
}az,af,bz,bf,aa,bb;
int main()
{
    long long n,m,q;
    scanf("%lld%lld%lld",&n,&m,&q);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        if(a[i]>=0)
        {
            A[i]=a[i];
        }
        else
        {
            A[i]=1e18;
        }
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&b[i]);
        if(b[i]>=0)
        {
            B[i]=b[i];
        }
        else
        {
            B[i]=1e18;
        }
    }
    aa.init(a,n);
    bb.init(b,m);
    az.init(A,n);
    bz.init(B,m);
    for(long long i=1;i<=n;i++)
    {
        if(a[i]<0)
        {
            A[i]=a[i];
        }
        else
        {
            A[i]=-1e18;
        }
    }
    for(long long i=1;i<=m;i++)
    {
        if(b[i]<0)
        {
            B[i]=b[i];
        }
        else
        {
            B[i]=-1e18;
        }
    }
    af.init(A,n);
    bf.init(B,m);
    while(q--)
    {
        long long l1,r1,l2,r2;
        scanf("%lld%lld%lld%lld",&l1,&r1,&l2,&r2);
        long long ans=-1e18;
        ans=max(aa.gmx(l1,r1)*(aa.gmx(l1,r1)>=0?bb.gmn(l2,r2):bb.gmx(l2,r2)),aa.gmn(l1,r1)*(aa.gmn(l1,r1)>=0?bb.gmn(l2,r2):bb.gmx(l2,r2)));
        if(af.gmx(l1,r1)!=-1e18)
        {
            ans=max(ans,af.gmx(l1,r1)*(af.gmx(l1,r1)>=0?bb.gmn(l2,r2):bb.gmx(l2,r2)));
        }
        if(az.gmn(l1,r1)!=1e18)
        {
            ans=max(ans,az.gmn(l1,r1)*(az.gmn(l1,r1)>=0?bb.gmn(l2,r2):bb.gmx(l2,r2)));
        }
        printf("%lld\n",ans);
    }
    return 0;
}
